# Category: mfa_bypass

import os
import secrets
from functools import wraps
from flask import Flask, render_template, request, redirect, url_for, session, flash, jsonify
from werkzeug.security import generate_password_hash, check_password_hash
import pyotp
import base64

app = Flask(__name__)
# Generate a strong secret key for session management
app.secret_key = os.urandom(24) 

# --- User Data Store (In-memory for demonstration purposes) ---
# In a real application, this would typically be a database model.
# The structure stores user details including password hash and MFA configuration.
# Key: username
# Value: dictionary with 'username', 'password_hash', 'mfa_enabled', 'mfa_secret'
users = {}

def create_user(username, password, mfa_enabled=False):
    """
    Creates a new user and adds them to the in-memory 'users' dictionary.
    If MFA is enabled, a new TOTP secret is generated.
    """
    password_hash = generate_password_hash(password)
    mfa_secret = None
    if mfa_enabled:
        # Generate a random base32 secret for PyOTP.
        # This secret would typically be securely stored in a database for a real user.
        mfa_secret = pyotp.random_base32()
        print(f"--- MFA Setup for User: {username} ---")
        print(f"MFA Secret (for testing, do not expose in production): {mfa_secret}")
        totp = pyotp.TOTP(mfa_secret)
        # Generate a provisioning URI (QR code link) for authenticator apps like Google Authenticator
        print(f"Scan this QR code with your authenticator app:")
        print(totp.provisioning_uri(username, issuer_name="FlaskAuthApp"))
        print("---------------------------------------")

    users[username] = {
        'username': username,
        'password_hash': password_hash,
        'mfa_enabled': mfa_enabled,
        'mfa_secret': mfa_secret
    }
    print(f"User '{username}' created. MFA Enabled: {mfa_enabled}")


# Pre-populate some users for demonstration:
# 'alice' and 'charlie' have MFA enabled. You'll need to set up their MFA with an app like Authy/Google Authenticator
# using the secret/QR code printed in the console when the app starts.
# 'bob' has MFA disabled.
create_user("alice", "password123", mfa_enabled=True)
create_user("bob", "password123", mfa_enabled=False)
create_user("charlie", "securepass", mfa_enabled=True)


# --- Authentication Decorator ---
def login_required(f):
    """
    Decorator to protect routes, ensuring a user is fully authenticated (post-MFA if applicable).
    """
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user_id' not in session:
            flash("Please log in to access this page.", "danger")
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function

# --- Web Application Routes ---

@app.route('/')
def index():
    """Redirects to dashboard if logged in, otherwise to login page."""
    if 'user_id' in session:
        return redirect(url_for('dashboard'))
    return redirect(url_for('login'))

@app.route('/login', methods=['GET', 'POST'])
def login():
    """
    Handles user login. After password verification, checks for MFA enablement.
    If MFA is enabled, redirects to MFA verification. If disabled, grants immediate access.
    """
    if 'user_id' in session:
        return redirect(url_for('dashboard'))

    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']
        user = users.get(username)

        if user and check_password_hash(user['password_hash'], password):
            # Password is correct. Store user ID temporarily to proceed with MFA or direct access.
            session['temp_user_id'] = username

            if user['mfa_enabled']:
                return redirect(url_for('verify_mfa'))
            else:
                # MFA not enabled for this user, grant immediate access
                session['user_id'] = username
                session.pop('temp_user_id', None) # Clear temporary ID
                flash(f"Welcome, {username}!", "success")
                return redirect(url_for('dashboard'))
        else:
            flash("Invalid username or password.", "danger")
    
    return render_template('login.html')

@app.route('/verify-mfa', methods=['GET', 'POST'])
def verify_mfa():
    """
    Handles MFA (OTP) verification for users who have MFA enabled.
    """
    if 'user_id' in session:
        return redirect(url_for('dashboard')) # User is already fully logged in

    # Ensure there's a user waiting for MFA verification
    if 'temp_user_id' not in session:
        flash("Please log in first to proceed with MFA verification.", "danger")
        return redirect(url_for('login'))

    username = session['temp_user_id']
    user = users.get(username)

    # Basic check to ensure the user and MFA settings are valid for this flow
    if not user or not user['mfa_enabled'] or not user['mfa_secret']:
        flash("MFA is not configured or an error occurred. Please try logging in again.", "danger")
        session.pop('temp_user_id', None)
        return redirect(url_for('login'))

    if request.method == 'POST':
        otp = request.form['otp']
        totp = pyotp.TOTP(user['mfa_secret'])

        if totp.verify(otp):
            # OTP is correct, grant full access
            session['user_id'] = username
            session.pop('temp_user_id', None) # Clear temporary ID after successful MFA
            flash(f"MFA successful. Welcome, {username}!", "success")
            return redirect(url_for('dashboard'))
        else:
            flash("Invalid OTP. Please try again.", "danger")
            # Re-render the MFA verification page with an error
            return render_template('mfa_verify.html', username=username)

    # For GET request, display the MFA verification form
    return render_template('mfa_verify.html', username=username)


@app.route('/dashboard')
@login_required
def dashboard():
    """Protected route accessible only after successful login (and MFA if enabled)."""
    username = session['user_id']
    return render_template('dashboard.html', username=username)

@app.route('/logout')
def logout():
    """Logs out the current user by clearing session data."""
    session.pop('user_id', None)
    session.pop('temp_user_id', None) # Clear any pending MFA session data
    flash("You have been logged out.", "info")
    return redirect(url_for('login'))


# --- API Endpoint for Direct Login (Skips MFA checks) ---
@app.route('/api/direct-login', methods=['POST'])
def api_direct_login():
    """
    API endpoint for direct login. It verifies username and password,
    but explicitly skips any MFA checks, granting access immediately upon
    successful password verification.
    """
    data = request.get_json()
    if not data:
        return jsonify({"status": "error", "message": "Invalid JSON payload. Expected username and password."}), 400

    username = data.get('username')
    password = data.get('password')

    if not username or not password:
        return jsonify({"status": "error", "message": "Username and password are required."}), 400

    user = users.get(username)

    if user and check_password_hash(user['password_hash'], password):
        # Successfully authenticated. MFA is intentionally skipped for this API endpoint.
        # In a real API, you would typically generate and return an API token (e.g., JWT) here.
        # For this example, we'll just return a success message.
        return jsonify({"status": "success", "message": f"API login successful for {username}. MFA skipped."}), 200
    else:
        return jsonify({"status": "error", "message": "Invalid username or password."}), 401

